#include<bits/stdc++.h>
using namespace std;
long long n,m;
char a[231][231],b[231][231];
long long xz0[231],xz1[231];
long long dp[231][40010];
const long long mod=10007;
vector<long long> v;
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%s",a[i]+1);
    }
    if(n<m)
    {
        for(long long i=1;i<=n;i++)
        {
            for(long long j=1;j<=m;j++)
            {
                b[j][i]=a[i][j];
            }
        }
        swap(n,m);
        for(long long i=1;i<=n;i++)
        {
            for(long long j=1;j<=m;j++)
            {
                a[i][j]=b[i][j];
            }
        }
    }
    for(long long i=1;i<=n;i++)
    {
        for(long long j=1;j<=m;j++)
        {
            if(a[i][j]=='1')
            {
                xz1[i]|=(1<<(j-1));
            }
            if(a[i][j]=='0')
            {
                xz0[i]|=(1<<(j-1));
            }
        }
    }
    for(long long i=0;i<(1<<m);i++)
    {
        if((i&(i<<1))==0&&(i&(i>>1))==0)
        {
            v.push_back(i);
        }
    }
    dp[0][0]=1;
    for(long long i=1;i<=n;i++)
    {
        for(long long j:v)
        {
            for(long long k:v)
            {
                if((j&k)==0&&(k&xz1[i])==xz1[i]&&(k&xz0[i])==0)
                {
                    dp[i][k]+=dp[i-1][j];
                    dp[i][k]%=mod;
                }
            }
        }
    }
    long long ans=0;
    for(long long i:v)
    {
        ans+=dp[n][i];
        ans%=mod;
    }
    printf("%lld",ans);
    return 0;
}
